-- Declare batch size and loop count
DECLARE @batchSize INT = 10000;
DECLARE @i INT = 0;
DECLARE @rows INT = 1;

WHILE @i < 30 AND @rows > 0
BEGIN
    DELETE FROM dbo.LessonCustomCategory
    WHERE Id IN (
        SELECT TOP (@batchSize) t.Id
        FROM dbo.LessonCustomCategory t
        INNER JOIN dbo.Lesson l ON t.LessonId = l.id
        INNER JOIN dbo.Subscription sub ON sub.id = l.SubscriptionId
        INNER JOIN dbo.AccountInfo a ON sub.accountInfoID = a.ID
        INNER JOIN dbo.AccountsToDelete atd ON a.ID = atd.AccountId
        WHERE 
            sub.OrganizationTypeId <> 2
            OR (
                sub.OrganizationTypeId = 2
                AND a.ID NOT IN (23382)
                AND sub.SubscriptionStatusID <> 1
                AND sub.dateSubscriptionStatusChanged <= DATEADD(MONTH, -6, GETDATE())
            )
        ORDER BY t.Id
    );

    SET @rows = @@ROWCOUNT;
    SET @i += 1;
END;

